// Get Apollo contacts (from Search Apollo, two nodes back)
const apolloData = $('Search Apollo').first().json;
//const contacts = apolloData.people || [];
const contacts = $('Search Apollo').all().map(item => item.json);
// Get exclusion rows from Google Sheets (direct input to this node)
const exclusionRows = $input.all().map(item => item.json);

// Build exclusion sets (lowercase for case-insensitive matching)
const excludedNames = exclusionRows
  .map(r => (r.company_name || '').toLowerCase().trim())
  .filter(Boolean);
const excludedDomains = exclusionRows
  .map(r => (r.domain || '').toLowerCase().replace(/^www\./, '').trim())
  .filter(Boolean);

function isExcluded(contact) {
  const name = (contact.organization_name || '').toLowerCase();
  const rawUrl = (contact.organization_website_url || '').toLowerCase();
  const domain = rawUrl
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .split('/')[0];
  return (
    excludedNames.some(n => n && name.includes(n)) ||
    excludedDomains.some(d => d && domain.includes(d))
  );
}

return contacts.filter(c => !isExcluded(c)).map(c => ({
  json: {
    first_name: c.first_name || '',
    last_name: c.last_name || '',
    full_name: `${c.first_name || ''} ${c.last_name || ''}`.trim(),
    title: c.title || '',
    email: c.email || '',
    company: c.organization_name || '',
    website: c.organization_website_url || '',
    city: c.city || '',
    state: c.state || ''
  }
}));

